  static constexpr const char* tablename = "ActiveUserView";
  static constexpr bool is_view = true;
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

std::vector<ActiveUser> query_active_users_posts() {
    using namespace sqlgen::literals;

    // 1. Connect to the SQLite database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");

    // 2. Create User and Post tables
    conn.execute(sqlgen::create_table<User>);
    conn.execute(sqlgen::create_table<Post>);

    // 3. Build the query using sqlgen's fluent interface
    auto query = sqlgen::select_from<User>("user_id", "username")
                 .as("u")
                 .join<Post>("p", "u.user_id"_c == "p.user_id"_c)
                 .where("p.created_at"_c >= "2025-12-01" && "p.created_at"_c <= "2025-12-31")
                 .distinct();

    // 4. Execute the query and return the results
    return query(conn).to<std::vector<ActiveUser>>;
}

}  // namespace query_active_users_posts
```

