TEST(sqlite, AnalyzeMathematicalOperations) {
    // Insert sample data
    std::vector<Product> products = {
        {1, "Laptop", 999.99, 10, 15.5},
        {2, "Mouse", 25.50, 100, 5.0},
        {3, "Keyboard", 150.75, 50, 10.0}
    };

