#include <optional>

namespace group_by_with_aggregations {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  std::string content;
};

struct Stats {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  int post_count;
  std::optional<double> avg_length;
};

/**
 * Description: This function retrieves user statistics including post count and average post length.
 * Returns: std::vector<Stats>.
 */
std::vector<Stats> group_by_with_aggregations() {
  // Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Build the query using SQLGen's fluent interface
  auto query = sqlgen::select_from<User>(
      "user_id"_c, "name"_c,
      sqlgen::count("post_id"_c).as("post_count"),
      sqlgen::avg(sqlgen::length("content"_c)).as("avg_length")
  )
  | sqlgen::join<Post>("user_id"_c == "user_id"_c)
  | sqlgen::group_by("user_id"_c, "name"_c)
  | sqlgen::to<std::vector<Stats>>;

  // Execute the query and return the results
  return query(conn).value();
}

}  // namespace group_by_with_aggregations

