 * This function demonstrates creating a table from a select query.
 * Returns: query value.
 */
inline auto create_table_as_select() {
    using namespace sqlgen::literals;

    // Create a column reference for the "value" field
    const auto value_col = "value"_c;

    // Build the SELECT query with WHERE condition
    const auto select_query = sqlgen::select_from<Source>(value_col)
                              | sqlgen::where(value_col > 100);

    // Create the table using the SELECT query
